-- =====================================================================
-- t2c_data — standalone bootstrap (schema + tables + RBAC seed + admin)
-- Generated by scripts/generate_bootstrap_sql.py from the ORM models and the
-- canonical RBAC seed. Brings an EMPTY PostgreSQL database to a runnable state
-- without Python/Alembic. For an EMPTY database; runs in a single transaction.
--
-- Usage:  psql "<DATABASE_URL>" -v ON_ERROR_STOP=1 -f scripts/sql/bootstrap.sql
--
-- NOTE: Airflow read-model VIEWS (vw_airflow_*) are created by Alembic/runtime,
-- not here; they are optional for the core system to run.
-- The default admin password is "admin123" — CHANGE IT IMMEDIATELY.
-- Prefer scripts/bootstrap_database.py in production (strong configured creds).
-- =====================================================================

BEGIN;

CREATE SCHEMA IF NOT EXISTS "t2c_data";
CREATE SCHEMA IF NOT EXISTS "t2c_ops";
SET search_path TO "t2c_data", public;

-- ---------------------------------------------------------------------
-- Schema (tables, constraints, indexes) — from SQLAlchemy models
-- ---------------------------------------------------------------------
CREATE TABLE t2c_data.audit_log_archive (
	id SERIAL NOT NULL, 
	created_at TIMESTAMP WITH TIME ZONE NOT NULL, 
	user_id INTEGER, 
	actor_name TEXT, 
	user_email TEXT, 
	ip INET, 
	user_agent TEXT, 
	action TEXT NOT NULL, 
	entity_type TEXT, 
	entity_id TEXT, 
	parent_entity_type TEXT, 
	parent_entity_id TEXT, 
	change_set_id TEXT, 
	change_type TEXT, 
	field_name TEXT, 
	source_module TEXT, 
	is_sensitive_change BOOLEAN DEFAULT 'false' NOT NULL, 
	sensitive_category TEXT, 
	route TEXT, 
	method TEXT, 
	status_code INTEGER, 
	request_id TEXT, 
	before_json JSONB, 
	after_json JSONB, 
	metadata_json JSONB, 
	PRIMARY KEY (id)
);
CREATE INDEX ix_t2c_data_audit_log_archive_source_module ON t2c_data.audit_log_archive (source_module);
CREATE INDEX ix_t2c_data_audit_log_archive_change_set_id ON t2c_data.audit_log_archive (change_set_id);
CREATE INDEX ix_audit_log_archive_source_created_at ON t2c_data.audit_log_archive (source_module, created_at);
CREATE INDEX ix_t2c_data_audit_log_archive_sensitive_category ON t2c_data.audit_log_archive (sensitive_category);
CREATE INDEX ix_t2c_data_audit_log_archive_field_name ON t2c_data.audit_log_archive (field_name);
CREATE INDEX ix_audit_log_archive_action_created_at ON t2c_data.audit_log_archive (action, created_at);
CREATE INDEX ix_t2c_data_audit_log_archive_created_at ON t2c_data.audit_log_archive (created_at);
CREATE INDEX ix_t2c_data_audit_log_archive_is_sensitive_change ON t2c_data.audit_log_archive (is_sensitive_change);
CREATE INDEX ix_t2c_data_audit_log_archive_change_type ON t2c_data.audit_log_archive (change_type);
CREATE INDEX ix_audit_log_archive_entity_created_at ON t2c_data.audit_log_archive (entity_type, entity_id, created_at);
CREATE INDEX ix_audit_log_archive_created_at ON t2c_data.audit_log_archive (created_at);
CREATE INDEX ix_t2c_data_audit_log_archive_user_id ON t2c_data.audit_log_archive (user_id);
CREATE TABLE t2c_data.access_log_archive (
	id SERIAL NOT NULL, 
	created_at TIMESTAMP WITH TIME ZONE NOT NULL, 
	user_id INTEGER, 
	actor_name TEXT, 
	user_email TEXT, 
	ip INET, 
	user_agent TEXT, 
	route TEXT NOT NULL, 
	method TEXT, 
