CREATE TABLE t2c_data.data_access_grants (
	id SERIAL NOT NULL, 
	user_id INTEGER, 
	group_id INTEGER, 
	effect VARCHAR(10) NOT NULL, 
	datasource_id INTEGER, 
	schema_id INTEGER, 
	table_id INTEGER, 
	note VARCHAR(255), 
	created_at TIMESTAMP WITH TIME ZONE DEFAULT now() NOT NULL, 
	updated_at TIMESTAMP WITH TIME ZONE DEFAULT now() NOT NULL, 
	PRIMARY KEY (id), 
	CONSTRAINT ck_data_access_grants_principal CHECK ((CASE WHEN user_id IS NOT NULL THEN 1 ELSE 0 END + CASE WHEN group_id IS NOT NULL THEN 1 ELSE 0 END) = 1), 
	CONSTRAINT ck_data_access_grants_scope CHECK ((CASE WHEN datasource_id IS NOT NULL THEN 1 ELSE 0 END + CASE WHEN schema_id IS NOT NULL THEN 1 ELSE 0 END + CASE WHEN table_id IS NOT NULL THEN 1 ELSE 0 END) = 1), 
	CONSTRAINT ck_data_access_grants_effect CHECK (effect IN ('allow', 'deny')), 
	CONSTRAINT uq_data_access_grants_unique UNIQUE (user_id, group_id, datasource_id, schema_id, table_id, effect), 
	FOREIGN KEY(user_id) REFERENCES t2c_data.users (id) ON DELETE CASCADE, 
	FOREIGN KEY(group_id) REFERENCES t2c_data.access_groups (id) ON DELETE CASCADE, 
	FOREIGN KEY(datasource_id) REFERENCES t2c_data.data_sources (id) ON DELETE CASCADE, 
	FOREIGN KEY(schema_id) REFERENCES t2c_data.schemas (id) ON DELETE CASCADE, 
	FOREIGN KEY(table_id) REFERENCES t2c_data.tables (id) ON DELETE CASCADE
);
