	reason TEXT, 
	status VARCHAR(20) NOT NULL, 
	reviewed_by_user_id INTEGER, 
	reviewed_at TIMESTAMP WITH TIME ZONE, 
	created_by_user_id INTEGER, 
	created_at TIMESTAMP WITH TIME ZONE DEFAULT now() NOT NULL, 
	updated_at TIMESTAMP WITH TIME ZONE DEFAULT now() NOT NULL, 
	PRIMARY KEY (id), 
	CONSTRAINT uq_dq_rule_suggestions_unique UNIQUE (profile_run_id, column_name, suggested_rule_type, dimension), 
	FOREIGN KEY(profile_run_id) REFERENCES t2c_data.dq_profile_runs (id) ON DELETE CASCADE, 
	FOREIGN KEY(table_id) REFERENCES t2c_data.tables (id) ON DELETE CASCADE, 
	FOREIGN KEY(column_id) REFERENCES t2c_data.columns (id) ON DELETE SET NULL, 
	FOREIGN KEY(reviewed_by_user_id) REFERENCES t2c_data.users (id) ON DELETE SET NULL, 
	FOREIGN KEY(created_by_user_id) REFERENCES t2c_data.users (id) ON DELETE SET NULL
);
CREATE INDEX ix_t2c_data_dq_rule_suggestions_reviewed_by_user_id ON t2c_data.dq_rule_suggestions (reviewed_by_user_id);
CREATE INDEX ix_dq_rule_suggestions_table_id ON t2c_data.dq_rule_suggestions (table_id);
CREATE INDEX ix_t2c_data_dq_rule_suggestions_table_id ON t2c_data.dq_rule_suggestions (table_id);
