CREATE INDEX ix_t2c_data_dq_rule_suggestions_status ON t2c_data.dq_rule_suggestions (status);
CREATE INDEX ix_t2c_data_dq_rule_suggestions_column_name ON t2c_data.dq_rule_suggestions (column_name);
CREATE INDEX ix_dq_rule_suggestions_status ON t2c_data.dq_rule_suggestions (status);
CREATE INDEX ix_t2c_data_dq_rule_suggestions_column_id ON t2c_data.dq_rule_suggestions (column_id);
CREATE INDEX ix_t2c_data_dq_rule_suggestions_profile_run_id ON t2c_data.dq_rule_suggestions (profile_run_id);
